  ('elementary-7fec267e-moex-00887', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '依憲法規定及司法院大法官解釋，關於人身自由之敘述，下列何者錯誤？', '["遣送出境前之強制收容屬於人民身體自由之剝奪，收容事由應以法律直接規定或法律具體明確授權之 命令定之", "基於防疫目的之強制隔離，已屬人身自由之剝奪", "「除現行犯之逮捕由法律另定外，非經司法或警察機關依法定程序，不得逮捕拘禁」之規定屬於憲法 保留事項", "遣送出境前之暫時收容雖非刑事逮捕拘禁，仍應由法院為之，始符憲法第8條之意旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00888', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '依憲法及司法院大法官解釋，關於言論自由的敘述，下列何者錯誤？', '["言論自由在於保障資訊之自由流通，使人民有取得充分資訊及自我實現之機會", "商業廣告係利用傳播方法，宣傳商品效能，以達招徠銷售為目的，不受言論自由之保障", "公共場所於不妨礙其通常使用方式之範圍內，亦得供人民之言論表達及意見溝通", "言論自由具有實現自我、溝通意見、追求真理之功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00889', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '依憲法增修條文及司法院大法官解釋，關於總統之地位與職權，下列敘述何者錯誤？', '["總統於戒嚴或緊急命令生效期間，不得解散立法院", "總統雖為國家元首，但完全不具最高行政首長地位", "總統為決定國家安全有關大政方針，得設國家安全會議及所屬國家安全局，其組織以法律定之", "總統發布行政院院長與依憲法經立法院同意任命人員之任免命令及解散立法院之命令，無須行政院院 長之副署"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00890', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '道路交通管理處罰條例規定，汽車駕駛人無駕駛執照而駕駛者，處新臺幣六千元以上一萬二千元以下罰 鍰，並當場禁止其駕駛。下列敘述何者正確？', '["主管機關對於個案中違規駕駛人裁處罰鍰之額度，享有自由行使裁量之權限", "主管機關對於是否當場禁止違規駕駛人駕駛，應依法律授權目的行使裁量權", "對於初次違規之駕駛人，主管機關皆應裁處最低罰鍰額度，以符合比例原則", "對於具有特殊情形之個案，不適用統一裁罰基準表決定罰鍰額度，並未違法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00891', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者不得依行政執行法規定，移送強制執行？', '["交通違規罰單", "支付命令", "怠金", "核課稅額通知書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00892', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於法明確性原則之敘述，下列何者錯誤？', '["法規內運用不確定法律概念或概括條款，一概違反明確性原則", "法律雖以抽象概念表示，不論其為不確定法律概念或概括條款，均須無違明確性之要求", "對人民權益影響越大者，授權之明確程度應越高", "法律文義非難以理解，且為受規範者所得預見，並可經由司法審查加以確認者，即不違明確性原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
